#include "b_tree.h"
#include <stdlib.h>
#include <stdbool.h>

#define T 3
#define MAX_KEYS (2 * T - 1)
#define MAX_CHILDREN (2 * T)

typedef struct BTreeNode {
    int keys[MAX_KEYS];
    struct BTreeNode* children[MAX_CHILDREN];
    int n;
    bool leaf;
} BTreeNode;

static BTreeNode* create_node(bool leaf) {
    BTreeNode* node = (BTreeNode*)calloc(1, sizeof(BTreeNode));
    node->leaf = leaf;
    node->n = 0;
    return node;
}

static void split_child(BTreeNode* parent, int i) {
    BTreeNode* full = parent->children[i];
    BTreeNode* new_node = create_node(full->leaf);
    new_node->n = T - 1;
    for (int j = 0; j < T - 1; j++) {
        new_node->keys[j] = full->keys[j + T];
    }
    if (!full->leaf) {
        for (int j = 0; j < T; j++) {
            new_node->children[j] = full->children[j + T];
            full->children[j + T] = NULL;
        }
    }
    for (int j = parent->n; j > i; j--) {
        parent->children[j + 1] = parent->children[j];
    }
    parent->children[i + 1] = new_node;
    for (int j = parent->n - 1; j >= i; j--) {
        parent->keys[j + 1] = parent->keys[j];
    }
    parent->keys[i] = full->keys[T - 1];
    full->n = T - 1;
    parent->n++;
}

static void insert_non_full(BTreeNode* node, int key) {
    int i = node->n - 1;
    if (node->leaf) {
        while (i >= 0 && key < node->keys[i]) {
            node->keys[i + 1] = node->keys[i];
            i--;
        }
        node->keys[i + 1] = key;
        node->n++;
    } else {
        while (i >= 0 && key < node->keys[i]) i--;
        i++;
        if (node->children[i]->n == MAX_KEYS) {
            split_child(node, i);
            if (key > node->keys[i]) i++;
        }
        insert_non_full(node->children[i], key);
    }
}

static void inorder(BTreeNode* node, int* result, int* idx) {
    if (!node) return;
    for (int i = 0; i < node->n; i++) {
        if (!node->leaf) inorder(node->children[i], result, idx);
        result[(*idx)++] = node->keys[i];
    }
    if (!node->leaf) inorder(node->children[node->n], result, idx);
}

static void free_tree(BTreeNode* node) {
    if (!node) return;
    if (!node->leaf) {
        for (int i = 0; i <= node->n; i++) {
            free_tree(node->children[i]);
        }
    }
    free(node);
}

int* b_tree(int* arr, int n, int* out_size) {
    if (n == 0) {
        *out_size = 0;
        return NULL;
    }
    BTreeNode* root = create_node(true);
    for (int i = 0; i < n; i++) {
        if (root->n == MAX_KEYS) {
            BTreeNode* new_root = create_node(false);
            new_root->children[0] = root;
            split_child(new_root, 0);
            root = new_root;
        }
        insert_non_full(root, arr[i]);
    }
    int* result = (int*)malloc(n * sizeof(int));
    int idx = 0;
    inorder(root, result, &idx);
    *out_size = idx;
    free_tree(root);
    return result;
}

#include <vector>
#include <algorithm>

static const int T = 3;

struct BTreeNode {
    int keys[2 * T - 1];
    BTreeNode* children[2 * T];
    int n;
    bool leaf;
    BTreeNode() : n(0), leaf(true) {
        for (int i = 0; i < 2 * T; i++) children[i] = nullptr;
    }
    ~BTreeNode() {
        if (!leaf) {
            for (int i = 0; i <= n; i++) {
                delete children[i];
            }
        }
    }
};

static void splitChild(BTreeNode* parent, int i) {
    BTreeNode* full = parent->children[i];
    BTreeNode* newNode = new BTreeNode();
    newNode->leaf = full->leaf;
    newNode->n = T - 1;
    for (int j = 0; j < T - 1; j++) {
        newNode->keys[j] = full->keys[j + T];
    }
    if (!full->leaf) {
        for (int j = 0; j < T; j++) {
            newNode->children[j] = full->children[j + T];
            full->children[j + T] = nullptr;
        }
    }
    for (int j = parent->n; j > i; j--) {
        parent->children[j + 1] = parent->children[j];
    }
    parent->children[i + 1] = newNode;
    for (int j = parent->n - 1; j >= i; j--) {
        parent->keys[j + 1] = parent->keys[j];
    }
    parent->keys[i] = full->keys[T - 1];
    full->n = T - 1;
    parent->n++;
}

static void insertNonFull(BTreeNode* node, int key) {
    int i = node->n - 1;
    if (node->leaf) {
        while (i >= 0 && key < node->keys[i]) {
            node->keys[i + 1] = node->keys[i];
            i--;
        }
        node->keys[i + 1] = key;
        node->n++;
    } else {
        while (i >= 0 && key < node->keys[i]) i--;
        i++;
        if (node->children[i]->n == 2 * T - 1) {
            splitChild(node, i);
            if (key > node->keys[i]) i++;
        }
        insertNonFull(node->children[i], key);
    }
}

static void inorder(BTreeNode* node, std::vector<int>& result) {
    if (!node) return;
    for (int i = 0; i < node->n; i++) {
        if (!node->leaf) inorder(node->children[i], result);
        result.push_back(node->keys[i]);
    }
    if (!node->leaf) inorder(node->children[node->n], result);
}

std::vector<int> b_tree(std::vector<int> arr) {
    if (arr.empty()) return {};
    BTreeNode* root = new BTreeNode();
    for (int val : arr) {
        if (root->n == 2 * T - 1) {
            BTreeNode* newRoot = new BTreeNode();
            newRoot->leaf = false;
            newRoot->children[0] = root;
            splitChild(newRoot, 0);
            root = newRoot;
        }
        insertNonFull(root, val);
    }
    std::vector<int> result;
    inorder(root, result);
    delete root;
    return result;
}

using System.Collections.Generic;

public class BTree
{
    private const int T = 3;
    private const int MaxKeys = 2 * T - 1;

    private class Node
    {
        public List<int> Keys = new List<int>();
        public List<Node> Children = new List<Node>();
        public bool Leaf = true;
    }

    private static void SplitChild(Node parent, int i)
    {
        Node full = parent.Children[i];
        Node newNode = new Node { Leaf = full.Leaf };
        int mid = T - 1;
        for (int j = T; j < full.Keys.Count; j++)
            newNode.Keys.Add(full.Keys[j]);
        int median = full.Keys[mid];
        if (!full.Leaf)
        {
            for (int j = T; j < full.Children.Count; j++)
                newNode.Children.Add(full.Children[j]);
            full.Children.RemoveRange(T, full.Children.Count - T);
        }
        full.Keys.RemoveRange(mid, full.Keys.Count - mid);
        parent.Keys.Insert(i, median);
        parent.Children.Insert(i + 1, newNode);
    }

    private static void InsertNonFull(Node node, int key)
    {
        if (node.Leaf)
        {
            int pos = node.Keys.FindIndex(k => k > key);
            if (pos == -1) pos = node.Keys.Count;
            node.Keys.Insert(pos, key);
        }
        else
        {
            int i = node.Keys.Count - 1;
            while (i >= 0 && key < node.Keys[i]) i--;
            i++;
            if (node.Children[i].Keys.Count == MaxKeys)
            {
                SplitChild(node, i);
                if (key > node.Keys[i]) i++;
            }
            InsertNonFull(node.Children[i], key);
        }
    }

    private static void Inorder(Node node, List<int> result)
    {
        if (node == null) return;
        for (int i = 0; i < node.Keys.Count; i++)
        {
            if (!node.Leaf) Inorder(node.Children[i], result);
            result.Add(node.Keys[i]);
        }
        if (!node.Leaf) Inorder(node.Children[node.Keys.Count], result);
    }

    public static int[] Run(int[] arr)
    {
        if (arr.Length == 0) return new int[0];
        Node root = new Node();
        foreach (int v in arr)
        {
            if (root.Keys.Count == MaxKeys)
            {
                Node newRoot = new Node { Leaf = false };
                newRoot.Children.Add(root);
                SplitChild(newRoot, 0);
                root = newRoot;
            }
            InsertNonFull(root, v);
        }
        List<int> result = new List<int>();
        Inorder(root, result);
        return result.ToArray();
    }
}

