const t = 3
const maxKeys = 2*t - 1

type node struct {
	keys     [maxKeys]int
	children [maxKeys + 1]*node
	n        int
	leaf     bool
}

func newNode(leaf bool) *node {
	return &node{leaf: leaf}
}

func splitChild(parent *node, i int) {
	full := parent.children[i]
	nn := newNode(full.leaf)
	nn.n = t - 1
	for j := 0; j < t-1; j++ {
		nn.keys[j] = full.keys[j+t]
	}
	if !full.leaf {
		for j := 0; j < t; j++ {
			nn.children[j] = full.children[j+t]
			full.children[j+t] = nil
		}
	}
	for j := parent.n; j > i; j-- {
		parent.children[j+1] = parent.children[j]
	}
	parent.children[i+1] = nn
	for j := parent.n - 1; j >= i; j-- {
		parent.keys[j+1] = parent.keys[j]
	}
	parent.keys[i] = full.keys[t-1]
	full.n = t - 1
	parent.n++
}

func insertNonFull(nd *node, key int) {
	i := nd.n - 1
	if nd.leaf {
		for i >= 0 && key < nd.keys[i] {
			nd.keys[i+1] = nd.keys[i]
			i--
		}
		nd.keys[i+1] = key
		nd.n++
	} else {
		for i >= 0 && key < nd.keys[i] {
			i--
		}
		i++
		if nd.children[i].n == maxKeys {
			splitChild(nd, i)
			if key > nd.keys[i] {
				i++
			}
		}
		insertNonFull(nd.children[i], key)
	}
}

func inorder(nd *node, result *[]int) {
	if nd == nil {
		return
	}
	for i := 0; i < nd.n; i++ {
		if !nd.leaf {
			inorder(nd.children[i], result)
		}
		*result = append(*result, nd.keys[i])
	}
	if !nd.leaf {
		inorder(nd.children[nd.n], result)
	}
}

// BTree inserts values into a B-Tree and returns sorted inorder traversal.
func BTree(arr []int) []int {
	if len(arr) == 0 {
		return []int{}
	}
	root := newNode(true)
	for _, val := range arr {
		if root.n == maxKeys {
			newRoot := newNode(false)
			newRoot.children[0] = root
			splitChild(newRoot, 0)
			root = newRoot
		}
		insertNonFull(root, val)
	}
	result := []int{}
	inorder(root, &result)
	return result
}

import java.util.ArrayList;
import java.util.List;

public class BTree {
    private static final int T = 3;

    static class Node {
        int[] keys = new int[2 * T - 1];
        Node[] children = new Node[2 * T];
        int n = 0;
        boolean leaf = true;
    }

    public static int[] bTree(int[] arr) {
        if (arr.length == 0) return new int[0];

        Node root = new Node();

        for (int val : arr) {
            root = insert(root, val);
        }

        List<Integer> result = new ArrayList<>();
        inorder(root, result);
        return result.stream().mapToInt(Integer::intValue).toArray();
    }

    private static Node insert(Node root, int key) {
        if (root.n == 2 * T - 1) {
            Node newRoot = new Node();
            newRoot.leaf = false;
            newRoot.children[0] = root;
            splitChild(newRoot, 0);
            root = newRoot;
        }
        insertNonFull(root, key);
        return root;
    }

    private static void splitChild(Node parent, int i) {
        Node full = parent.children[i];
        Node newNode = new Node();
        newNode.leaf = full.leaf;
        newNode.n = T - 1;

        for (int j = 0; j < T - 1; j++) {
            newNode.keys[j] = full.keys[j + T];
        }
        if (!full.leaf) {
            for (int j = 0; j < T; j++) {
                newNode.children[j] = full.children[j + T];
            }
        }

        for (int j = parent.n; j > i; j--) {
            parent.children[j + 1] = parent.children[j];
        }
        parent.children[i + 1] = newNode;

        for (int j = parent.n - 1; j >= i; j--) {
            parent.keys[j + 1] = parent.keys[j];
        }
        parent.keys[i] = full.keys[T - 1];
        full.n = T - 1;
        parent.n++;
    }

    private static void insertNonFull(Node node, int key) {
        int i = node.n - 1;
        if (node.leaf) {
            while (i >= 0 && key < node.keys[i]) {
                node.keys[i + 1] = node.keys[i];
                i--;
            }
            node.keys[i + 1] = key;
            node.n++;
        } else {
            while (i >= 0 && key < node.keys[i]) {
                i--;
            }
            i++;
            if (node.children[i].n == 2 * T - 1) {
                splitChild(node, i);
                if (key > node.keys[i]) {
                    i++;
                }
            }
            insertNonFull(node.children[i], key);
        }
    }

    private static void inorder(Node node, List<Integer> result) {
        if (node == null) return;
        for (int i = 0; i < node.n; i++) {
            if (!node.leaf) {
                inorder(node.children[i], result);
            }
            result.add(node.keys[i]);
        }
        if (!node.leaf) {
            inorder(node.children[node.n], result);
        }
    }
}

private const val T = 3
private const val MAX_KEYS = 2 * T - 1

private class BTreeNode(var leaf: Boolean = true) {
    val keys = mutableListOf<Int>()
    val children = mutableListOf<BTreeNode>()
}

private fun splitChild(parent: BTreeNode, i: Int) {
    val full = parent.children[i]
    val newNode = BTreeNode(full.leaf)
    val mid = T - 1
    for (j in T until full.keys.size) {
        newNode.keys.add(full.keys[j])
    }
    val median = full.keys[mid]
    if (!full.leaf) {
        for (j in T until full.children.size) {
            newNode.children.add(full.children[j])
        }
        while (full.children.size > T) full.children.removeAt(full.children.size - 1)
    }
    while (full.keys.size > mid) full.keys.removeAt(full.keys.size - 1)
    parent.keys.add(i, median)
    parent.children.add(i + 1, newNode)
}

private fun insertNonFull(node: BTreeNode, key: Int) {
    if (node.leaf) {
        val pos = node.keys.indexOfFirst { it > key }.let { if (it == -1) node.keys.size else it }
        node.keys.add(pos, key)
    } else {
        var i = node.keys.size - 1
        while (i >= 0 && key < node.keys[i]) i--
        i++
        if (node.children[i].keys.size == MAX_KEYS) {
            splitChild(node, i)
            if (key > node.keys[i]) i++
        }
        insertNonFull(node.children[i], key)
    }
}

private fun inorder(node: BTreeNode?, result: MutableList<Int>) {
    if (node == null) return
    for (i in 0 until node.keys.size) {
        if (!node.leaf) inorder(node.children[i], result)
        result.add(node.keys[i])
    }
    if (!node.leaf) inorder(node.children[node.keys.size], result)
}

fun bTree(arr: IntArray): IntArray {
    if (arr.isEmpty()) return intArrayOf()
    var root = BTreeNode(true)
    for (v in arr) {
        if (root.keys.size == MAX_KEYS) {
            val newRoot = BTreeNode(false)
            newRoot.children.add(root)
            splitChild(newRoot, 0)
            root = newRoot
        }
        insertNonFull(root, v)
    }
    val result = mutableListOf<Int>()
    inorder(root, result)
    return result.toIntArray()
}

def b_tree(arr: list[int]) -> list[int]:
    T = 3  # minimum degree

    class Node:
        def __init__(self, leaf=True):
            self.keys = []
            self.children = []
            self.leaf = leaf

    root = None

    def split_child(parent, i):
        full = parent.children[i]
        new_node = Node(leaf=full.leaf)
        mid = T - 1
        parent.keys.insert(i, full.keys[mid])
        new_node.keys = full.keys[mid + 1:]
        full.keys = full.keys[:mid]
        if not full.leaf:
            new_node.children = full.children[T:]
            full.children = full.children[:T]
        parent.children.insert(i + 1, new_node)

    def insert_non_full(node, key):
        i = len(node.keys) - 1
        if node.leaf:
            node.keys.append(0)
            while i >= 0 and key < node.keys[i]:
                node.keys[i + 1] = node.keys[i]
                i -= 1
            node.keys[i + 1] = key
        else:
            while i >= 0 and key < node.keys[i]:
                i -= 1
            i += 1
            if len(node.children[i].keys) == 2 * T - 1:
                split_child(node, i)
                if key > node.keys[i]:
                    i += 1
            insert_non_full(node.children[i], key)

    def insert(key):
        nonlocal root
        if root is None:
            root = Node(leaf=True)
            root.keys.append(key)
            return
        if len(root.keys) == 2 * T - 1:
            new_root = Node(leaf=False)
            new_root.children.append(root)
            split_child(new_root, 0)
            root = new_root
        insert_non_full(root, key)

    def inorder(node):
        if node is None:
            return []
        result = []
        for i in range(len(node.keys)):
            if not node.leaf:
                result.extend(inorder(node.children[i]))
            result.append(node.keys[i])
        if not node.leaf:
            result.extend(inorder(node.children[len(node.keys)]))
        return result

    for val in arr:
        insert(val)

    return inorder(root)

const T: usize = 3;
const MAX_KEYS: usize = 2 * T - 1;

struct BTreeNode {
    keys: Vec<i32>,
    children: Vec<BTreeNode>,
    leaf: bool,
}

impl BTreeNode {
    fn new(leaf: bool) -> Self {
        BTreeNode {
            keys: Vec::new(),
            children: Vec::new(),
            leaf,
        }
    }
}

fn split_child(parent: &mut BTreeNode, i: usize) {
    let full = &mut parent.children[i];
    let mut new_node = BTreeNode::new(full.leaf);
    new_node.keys = full.keys.split_off(T);
    let median = full.keys.pop().unwrap();
    if !full.leaf {
        new_node.children = full.children.split_off(T);
    }
    parent.keys.insert(i, median);
    parent.children.insert(i + 1, new_node);
}

fn insert_non_full(node: &mut BTreeNode, key: i32) {
    if node.leaf {
        let pos = node.keys.iter().position(|&k| k > key).unwrap_or(node.keys.len());
        node.keys.insert(pos, key);
    } else {
        let mut i = node.keys.len();
        while i > 0 && key < node.keys[i - 1] {
            i -= 1;
        }
        if node.children[i].keys.len() == MAX_KEYS {
            split_child(node, i);
            if key > node.keys[i] {
                i += 1;
            }
        }
        insert_non_full(&mut node.children[i], key);
    }
}

fn inorder(node: &BTreeNode, result: &mut Vec<i32>) {
    for i in 0..node.keys.len() {
        if !node.leaf {
            inorder(&node.children[i], result);
        }
        result.push(node.keys[i]);
    }
    if !node.leaf {
        inorder(&node.children[node.keys.len()], result);
    }
}

pub fn b_tree(arr: &[i32]) -> Vec<i32> {
    if arr.is_empty() {
        return vec![];
    }
    let mut root = BTreeNode::new(true);
    for &val in arr {
        if root.keys.len() == MAX_KEYS {
            let mut new_root = BTreeNode::new(false);
            let old_root = std::mem::replace(&mut root, BTreeNode::new(true));
            new_root.children.push(old_root);
            split_child(&mut new_root, 0);
            root = new_root;
        }
        insert_non_full(&mut root, val);
    }
    let mut result = Vec::new();
    inorder(&root, &mut result);
    result
}

object BTree {
  private val T = 3
  private val MaxKeys = 2 * T - 1

  private class Node(var leaf: Boolean = true) {
    val keys = scala.collection.mutable.ArrayBuffer[Int]()
    val children = scala.collection.mutable.ArrayBuffer[Node]()
  }

  private def splitChild(parent: Node, i: Int): Unit = {
    val full = parent.children(i)
    val newNode = new Node(full.leaf)
    val mid = T - 1
    for (j <- T until full.keys.size) newNode.keys += full.keys(j)
    val median = full.keys(mid)
    if (!full.leaf) {
      for (j <- T until full.children.size) newNode.children += full.children(j)
      full.children.trimEnd(full.children.size - T)
    }
    full.keys.trimEnd(full.keys.size - mid)
    parent.keys.insert(i, median)
    parent.children.insert(i + 1, newNode)
  }

  private def insertNonFull(node: Node, key: Int): Unit = {
    if (node.leaf) {
      val pos = node.keys.indexWhere(_ > key) match {
        case -1 => node.keys.size
        case p  => p
      }
      node.keys.insert(pos, key)
    } else {
      var i = node.keys.size - 1
      while (i >= 0 && key < node.keys(i)) i -= 1
      i += 1
      if (node.children(i).keys.size == MaxKeys) {
        splitChild(node, i)
        if (key > node.keys(i)) i += 1
      }
      insertNonFull(node.children(i), key)
    }
  }

  private def inorder(node: Node, result: scala.collection.mutable.ArrayBuffer[Int]): Unit = {
    if (node == null) return
    for (i <- 0 until node.keys.size) {
      if (!node.leaf) inorder(node.children(i), result)
      result += node.keys(i)
    }
    if (!node.leaf) inorder(node.children(node.keys.size), result)
  }

  def bTree(arr: Array[Int]): Array[Int] = {
    if (arr.isEmpty) return Array.empty[Int]
    var root = new Node(true)
    for (v <- arr) {
      if (root.keys.size == MaxKeys) {
        val newRoot = new Node(false)
        newRoot.children += root
        splitChild(newRoot, 0)
        root = newRoot
      }
      insertNonFull(root, v)
    }
    val result = scala.collection.mutable.ArrayBuffer[Int]()
    inorder(root, result)
    result.toArray
  }
}

private let T_ORDER = 3
private let MAX_KEYS = 2 * T_ORDER - 1

private class BTreeNode {
    var keys: [Int] = []
    var children: [BTreeNode] = []
    var leaf: Bool

    init(leaf: Bool = true) {
        self.leaf = leaf
    }
}

private func splitChild(_ parent: BTreeNode, _ i: Int) {
    let full = parent.children[i]
    let newNode = BTreeNode(leaf: full.leaf)
    let mid = T_ORDER - 1
    newNode.keys = Array(full.keys[T_ORDER...])
    let median = full.keys[mid]
    if !full.leaf {
        newNode.children = Array(full.children[T_ORDER...])
        full.children = Array(full.children[..<T_ORDER])
    }
    full.keys = Array(full.keys[..<mid])
    parent.keys.insert(median, at: i)
    parent.children.insert(newNode, at: i + 1)
}

private func insertNonFull(_ node: BTreeNode, _ key: Int) {
    if node.leaf {
        let pos = node.keys.firstIndex(where: { $0 > key }) ?? node.keys.count
        node.keys.insert(key, at: pos)
    } else {
        var i = node.keys.count - 1
        while i >= 0 && key < node.keys[i] { i -= 1 }
        i += 1
        if node.children[i].keys.count == MAX_KEYS {
            splitChild(node, i)
            if key > node.keys[i] { i += 1 }
        }
        insertNonFull(node.children[i], key)
    }
}

private func inorder(_ node: BTreeNode?, _ result: inout [Int]) {
    guard let node = node else { return }
    for i in 0..<node.keys.count {
        if !node.leaf { inorder(node.children[i], &result) }
        result.append(node.keys[i])
    }
    if !node.leaf { inorder(node.children[node.keys.count], &result) }
}

func bTree(_ arr: [Int]) -> [Int] {
    if arr.isEmpty { return [] }
    var root = BTreeNode(leaf: true)
    for val in arr {
        if root.keys.count == MAX_KEYS {
            let newRoot = BTreeNode(leaf: false)
            newRoot.children.append(root)
            splitChild(newRoot, 0)
            root = newRoot
        }
        insertNonFull(root, val)
    }
    var result: [Int] = []
    inorder(root, &result)
    return result
}

const T = 3;
const MAX_KEYS = 2 * T - 1;

class BTreeNode {
    keys: number[] = [];
    children: BTreeNode[] = [];
    leaf: boolean;

    constructor(leaf: boolean = true) {
        this.leaf = leaf;
    }
}

function splitChild(parent: BTreeNode, i: number): void {
    const full = parent.children[i];
    const newNode = new BTreeNode(full.leaf);
    newNode.keys = full.keys.splice(T);
    parent.keys.splice(i, 0, full.keys.pop()!);
    if (!full.leaf) {
        newNode.children = full.children.splice(T);
    }
    parent.children.splice(i + 1, 0, newNode);
}

function insertNonFull(node: BTreeNode, key: number): void {
    if (node.leaf) {
        let i = node.keys.length - 1;
        node.keys.push(0);
        while (i >= 0 && key < node.keys[i]) {
            node.keys[i + 1] = node.keys[i];
            i--;
        }
        node.keys[i + 1] = key;
    } else {
        let i = node.keys.length - 1;
        while (i >= 0 && key < node.keys[i]) i--;
        i++;
        if (node.children[i].keys.length === MAX_KEYS) {
            splitChild(node, i);
            if (key > node.keys[i]) i++;
        }
        insertNonFull(node.children[i], key);
    }
}

function inorder(node: BTreeNode | null, result: number[]): void {
    if (!node) return;
    for (let i = 0; i < node.keys.length; i++) {
        if (!node.leaf) inorder(node.children[i], result);
        result.push(node.keys[i]);
    }
    if (!node.leaf) inorder(node.children[node.keys.length], result);
}

export function bTree(arr: number[]): number[] {
    if (arr.length === 0) return [];
    let root = new BTreeNode(true);
    for (const val of arr) {
        if (root.keys.length === MAX_KEYS) {
            const newRoot = new BTreeNode(false);
            newRoot.children.push(root);
            splitChild(newRoot, 0);
            root = newRoot;
        }
        insertNonFull(root, val);
    }
    const result: number[] = [];
    inorder(root, result);
    return result;
}
